-- ============================================================================
-- Reset to France · mid-range · Sofia + 15 new
--
-- THREE sections, run together:
--
--   1) Promote Sofía Romero from budget tier → mid_range "comfortable".
--      Fills the explicit meta budget keys (daily_spend_per_pax_eur,
--      hotel_budget_per_night_pax_eur) so the Day-form per-stop warnings
--      + Day-summary "over budget" comparisons actually fire. Without
--      these keys window._currentDailyBudget is null and the warning
--      system silently skips.
--
--   2) DESTRUCTIVE WIPE — every non-Sofia traveler, plan, itinerary_item,
--      set, set_assignment is removed. Sets are deleted first so the FK
--      cascade clears plans + items + assignments. Then orphan-plan
--      sweep (defensive) then non-Sofia travelers.
--
--   3) Insert 15 new travelers (persons 03-17), seed_batch='02'.
--      All mid_range tier, daily €130-180 / hotel €115-170 spread across
--      "entry-mid" → "comfortable-mid". Multi-unit France trips, each
--      unit 2D1N or 3D2N, realistic train/flight handoffs. No bond.
--
-- Re-run safety: section 1 is idempotent. Section 2 is destructive (wipes
-- on every run). Section 3 has explicit UUIDs — re-running will fail on
-- unique violation, which is the intended safety net (re-runs must wipe
-- via section 2 first).
-- ============================================================================


-- ────────────────────────────────────────────────────────────────────────
-- SECTION 1 · Promote Sofía to mid-range "comfortable"
-- ────────────────────────────────────────────────────────────────────────
-- Mid-range comfortable profile: daily €150 / hotel €140, occasional
-- splurges OK, planner-recommends booking. Pace moderate, intensity
-- moderate, standard daily timing. Updates all 3 of her units (1=Saint-Malo,
-- 2=Mont-Saint-Michel, 3=Paris) via the shared meta->>'person_id'='02'.
-- Mirrors values into the legacy budget_per_day/hotel_budget columns so
-- the brief's fallback renderer agrees with the meta source of truth.
UPDATE public.travelers
SET    budget_per_day = 150,
       hotel_budget   = 140,
       meta = meta || jsonb_build_object(
         'budget_tier',                   'mid_range',
         'daily_spend_per_pax_eur',       150,
         'hotel_budget_per_night_pax_eur',140,
         'splurge_willingness',           'occasional',
         'booking_authority',             'planner_recommends',
         'pace',                          'moderate',
         'intensity',                     'moderate',
         'daily_timing',                  'standard',
         'previous_visits',               'first_time',
         'mobility',                      'none',
         'dietary_restrictions',          'none',
         'languages',                     to_jsonb(ARRAY['Spanish','English']::text[]),
         'occasion',                      'solo_travel',
         'accommodation_type',            'boutique',
         'room_type',                     'Private room with breakfast',
         'accommodation_musthaves',       to_jsonb(ARRAY['Central location','Wifi','Quiet street','Photo-iconic views']::text[]),
         'dining_style',                  'local_authentic',
         'cuisine_interests',             to_jsonb(ARRAY['Local bistros','Pastries','Cafes','Crêpes','Wine bars']::text[])
       )
WHERE  meta->>'seed_batch' = '01'
  AND  meta->>'person_id'  = '02';


-- ────────────────────────────────────────────────────────────────────────
-- SECTION 2 · DESTRUCTIVE WIPE of everything except Sofía
-- ────────────────────────────────────────────────────────────────────────
-- Order matters: delete sets first (cascades plans + items + assignments),
-- then defensive orphan-plan sweep, then non-Sofia traveler rows.

-- 2a. Delete sets that have NO plan tied to Sofía. The FK cascade does
--     the heavy lifting (plans, itinerary_items, set_assignments all gone).
DELETE FROM public.sets s
WHERE  NOT EXISTS (
  SELECT 1 FROM public.plans p
  WHERE  p.set_id = s.id
    AND  p.traveler_id IN (
      SELECT id FROM public.travelers
      WHERE  meta->>'seed_batch' = '01' AND meta->>'person_id' = '02'
    )
);

-- 2b. Orphan plans that somehow survived (mixed-traveler sets, NULL
--     traveler_id legacy rows). itinerary_items CASCADE off plans.
DELETE FROM public.plans
WHERE  traveler_id IS NULL
   OR  traveler_id NOT IN (
     SELECT id FROM public.travelers
     WHERE  meta->>'seed_batch' = '01' AND meta->>'person_id' = '02'
   );

-- 2c. Every traveler row that isn't Sofía's seed.
DELETE FROM public.travelers
WHERE  NOT (meta->>'seed_batch' = '01' AND meta->>'person_id' = '02');


-- ────────────────────────────────────────────────────────────────────────
-- SECTION 3 · Insert 15 new mid-range France travelers (persons 03-17)
-- ────────────────────────────────────────────────────────────────────────
-- All seed_batch='02' so they're distinct from Sofia's '01' seed and the
-- rollback "DELETE WHERE seed_batch='02'" cleanly removes this batch.
--
-- ID scheme: a0000001-0000-4000-8000-PPPPUUUU0000
--   PPPP = person_id zero-padded ("0003" .. "0017")
--   UUUU = unit_order zero-padded ("0001", "0002", "0003")
--
-- Each row: (id, name, phone, destination, traveler_type, arrival_date,
--           arrival_time, duration, group_size, special_notes, status,
--           planner_payout, requires_bond, bond_amount, meta)
--
-- planner_payout = 48 (matches Sofía's existing override; commission
--                      table in dashboard.html computes the actual fee
--                      per unit + continuity bonus separately).
-- requires_bond = false (mid-range tier doesn't need bond).
INSERT INTO public.travelers (id, name, phone, destination, traveler_type, arrival_date, arrival_time, duration, group_size, special_notes, status, planner_payout, requires_bond, bond_amount, meta) VALUES

