-- ────────────────────────────────────────────────────────────────────────
-- Verify
-- ────────────────────────────────────────────────────────────────────────
-- a) Sofía's row now shows mid_range tier + explicit budget meta.
SELECT meta->>'unit_order' AS unit, destination, arrival_date, arrival_time,
       meta->>'budget_tier' AS tier,
       (meta->>'daily_spend_per_pax_eur')::int AS daily,
       (meta->>'hotel_budget_per_night_pax_eur')::int AS hotel_night,
       meta->>'splurge_willingness' AS splurge
FROM   public.travelers
WHERE  meta->>'seed_batch'='01' AND meta->>'person_id'='02'
ORDER  BY (meta->>'unit_order')::int;

-- b) Only Sofía + the 15 new persons remain.
SELECT meta->>'seed_batch' AS batch, meta->>'person_id' AS person,
       name, COUNT(*) AS unit_rows
FROM   public.travelers
GROUP  BY batch, person, name
ORDER  BY batch, person;
-- → 16 rows expected (1 Sofía + 15 new)

-- c) Spread of tiers + budgets (should all be mid_range, daily 130-180).
SELECT meta->>'budget_tier' AS tier,
       MIN((meta->>'daily_spend_per_pax_eur')::int) AS daily_min,
       MAX((meta->>'daily_spend_per_pax_eur')::int) AS daily_max,
       COUNT(DISTINCT meta->>'person_id') AS persons
FROM   public.travelers
GROUP  BY tier;
